            )}
          </section>

          <section className="panel-card">
            <div className="section-heading">
              <strong>Matching links</strong>
              <span className="section-meta">{results.links.length} result{results.links.length === 1 ? "" : "s"}</span>
            </div>
            {results.links.length === 0 ? (
              <p>No private links matched this query.</p>
            ) : (
              <div className="link-list">
                {results.links.map((link) => (
                  <article className="link-list-item" key={link.id}>
                    <div className="link-list-heading">
                      <div className="note-meta note-meta-leading">
                        <span>Private link</span>
                      </div>
                      <a className="note-list-link" href={link.url} rel="noopener noreferrer" target="_blank">
                        {link.title}
                      </a>
                      <p className="link-url">{link.url}</p>
                    </div>
                    {link.summary ? <p className="link-summary">AI summary: {link.summary}</p> : null}
                    <EnrichmentStatusBlock state={link.enrichment} />
                    <div className="link-list-footer">
                      <div className="tag-list" aria-label="Link tags">
                        {link.tags.length === 0 ? (
                          <span className="tag-pill tag-pill-muted">No generated tags yet</span>
                        ) : (
                          link.tags.map((tag) => (
                            <span className="tag-pill" key={tag.id}>
                              {tag.name}
                            </span>
                          ))
                        )}
                      </div>
                      <div className="note-meta">
                        <span>Updated</span>
                        <span>{new Intl.DateTimeFormat("en", { dateStyle: "medium" }).format(link.updatedAt)}</span>
                      </div>
                    </div>
                  </article>
                ))}
              </div>
            )}
          </section>
        </div>
      ) : (
        <section className="panel-card">
          <div className="section-heading">
            <strong>Search scope</strong>
            <span className="section-meta">v1 boundaries</span>
          </div>
          <p>Search matches note titles, link titles, link URLs, and shared tag names. Note bodies and link summaries stay out of scope in v1.</p>
        </section>
      )}
    </div>
  );
}

import "dotenv/config";

export const AI_REAL_TEST_TAG = "@ai-real";
export const AI_REAL_ENV_KEYS = ["LLM_BASE", "TOKEN", "MODEL"] as const;
export const AI_REAL_ENV_MESSAGE = `Requires ${AI_REAL_ENV_KEYS.join(", ")}.`;

export function getAiRealEnvStatus() {
  const missing = AI_REAL_ENV_KEYS.filter((name) => !process.env[name]?.trim());

  return {
    configured: missing.length === 0,
    missing
  };
}

export function hasAiRealEnv() {
  return getAiRealEnvStatus().configured;
}

import "dotenv/config";

import { expect, test } from "@playwright/test";

import { AI_REAL_ENV_MESSAGE, AI_REAL_TEST_TAG, hasAiRealEnv } from "./ai-real";

test.describe.configure({ mode: "serial" });
test.skip(!hasAiRealEnv(), AI_REAL_ENV_MESSAGE);

test(`owner link enrichment completes against the real Mina endpoint ${AI_REAL_TEST_TAG}`, async ({ page }) => {
  const username = process.env.OWNER_USERNAME ?? "owner";
  const password = process.env.OWNER_PASSWORD ?? "password";
  const uniqueId = `${Date.now()}`;
  const title = `AI enriched link ${uniqueId}`;
  const url = `https://example.com/ai-enriched-link-${uniqueId}`;

  await page.goto("/login");
  await page.getByLabel("Username").fill(username);
  await page.getByLabel("Password").fill(password);
  await page.getByRole("button", { name: "Sign in" }).click();

  await expect(page).toHaveURL(/\/app$/);
  await page.getByRole("link", { name: "Links" }).click();
  await expect(page).toHaveURL(/\/app\/links$/);

  await page.getByRole("textbox", { name: /^URL$/ }).fill(url);
  await page.getByRole("textbox", { name: /^Title$/ }).fill(title);
  await page.getByRole("button", { name: "Save link" }).click();

  await expect(page).toHaveURL(/\/app\/links\?saved=1$/);
  const linkCard = page.locator("article").filter({ has: page.getByRole("link", { name: title }) });
  await expect(linkCard).toContainText("AI pending");
  await expect(linkCard).toContainText("AI ready", { timeout: 60000 });
  await expect(linkCard.getByTestId("link-ai-summary")).toBeVisible();
  await expect(linkCard.getByTestId("link-ai-tags").locator(".tag-pill")).not.toHaveCount(0);

  const generatedTag = (await linkCard.getByTestId("link-ai-tags").locator(".tag-pill").first().textContent())?.trim();

  await page.goto(`/app/search?q=${encodeURIComponent(generatedTag ?? "")}`);
  const searchResult = page.locator("article").filter({ has: page.getByRole("link", { name: title }) });
  await expect(searchResult).toContainText("AI ready");
  await expect(searchResult).toContainText("AI summary:");

  await page.goto(`/app/tags?tag=${encodeURIComponent(generatedTag ?? "")}`);
  const taggedResult = page.locator("article").filter({ has: page.getByRole("link", { name: title }) });
  await expect(taggedResult).toContainText("AI ready");
  await expect(taggedResult).toContainText("AI summary:");
});

